document.addEventListener('DOMContentLoaded', function() {
  // 1. Hide duplicate "Get the eBook" nav item
  var navLinks = document.querySelectorAll('header .menu-link');
  navLinks.forEach(function(link) {
    if (link.textContent.trim().includes('Get the eBook')) {
      var mi = link.closest('.menu-item');
      if (mi) mi.style.display = 'none';
    }
  });

  // 2. Add Canada flags to article images
  function addFlags() {
    var wrappers = document.querySelectorAll('.eael-entry-thumbnail');
    wrappers.forEach(function(w) {
      if (w.querySelector('.canada-flag-badge')) return;
      var flag = document.createElement('div');
      flag.className = 'canada-flag-badge';
      flag.innerHTML = 'u{1F341}';
      w.style.position = 'relative';
      w.appendChild(flag);
    });
  }
  addFlags();
  setTimeout(addFlags, 1500);

  // 3. Fix article grid display
  function fixGrid() {
    var grid = document.querySelector('.eael-post-grid.eael-post-appender');
    if (grid) { grid.style.overflow = 'visible'; grid.style.height = 'auto'; }
    var cont = document.querySelector('.eael-post-grid-container');
    if (cont) { cont.style.overflow = 'visible'; cont.style.height = 'auto'; }
  }
  fixGrid();
  setTimeout(fixGrid, 1500);

  // 4. Center author section
  var authorEl = document.querySelector('.elementor-element-mag-author-001');
  if (authorEl) { authorEl.style.display = 'flex'; authorEl.style.justifyContent = 'center'; }
});// MoneyAbroadGuide - Newcomers to Canada Page
