document.addEventListener('DOMContentLoaded', function() {
  // 1. Hide duplicate "Get the eBook" nav item
  document.querySelectorAll('header .menu-link').forEach(function(link) {
    if (link.textContent.trim().includes('Get the eBook')) {
      var mi = link.closest('.menu-item');
      if (mi) mi.style.display = 'none';
    }
  });

  // 2. Add Canada flag badges to article images
  function addFlags() {
    document.querySelectorAll('.eael-entry-thumbnail').forEach(function(w) {
      if (w.querySelector('.canada-flag-badge')) return;
      var flag = document.createElement('div');
      flag.className = 'canada-flag-badge';
      flag.textContent = '🍁';
      flag.style.cssText = 'position:absolute!important;top:8px!important;right:8px!important;background:rgba(255,255,255,0.95)!important;border:2px solid #D52B1E!important;border-radius:50%!important;width:36px!important;height:36px!important;display:flex!important;align-items:center!important;justify-content:center!important;font-size:20px!important;z-index:10!important;box-shadow:0 2px 6px rgba(0,0,0,0.3)!important;line-height:36px!important;text-align:center!important;';
      w.style.position = 'relative';
      w.appendChild(flag);
    });
  }
  addFlags();

  // 3. Fix article grid height (EAEL uses absolute positioning)
  function fixGrid() {
    var grid = document.querySelector('.eael-post-grid.eael-post-appender');
    var container = document.querySelector('.eael-post-grid-container');
    if (!grid || !container) return;
    var articles = grid.querySelectorAll('article.eael-grid-post');
    if (articles.length === 0) return;
    var gridRect = grid.getBoundingClientRect();
    var scrollY = window.scrollY || 0;
    var maxBottom = 0;
    articles.forEach(function(a) {
      var bottom = a.getBoundingClientRect().bottom + scrollY;
      if (bottom > maxBottom) maxBottom = bottom;
    });
    var needed = maxBottom - (gridRect.top + scrollY) + 20;
    if (needed > 200) {
      grid.style.setProperty('height', needed + 'px', 'important');
      grid.style.setProperty('min-height', needed + 'px', 'important');
      container.style.setProperty('min-height', (needed + 20) + 'px', 'important');
    }
    addFlags();
  }
  fixGrid();
  setTimeout(fixGrid, 800);
  setTimeout(fixGrid, 2000);

  // 4. Center author section
  var el = document.querySelector('.elementor-element-mag-author-001');
  if (el) { el.style.display = 'flex'; el.style.justifyContent = 'center'; }
});
